import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils;

public class XssSecureCode {
    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly escape user input to prevent XSS
        String sanitizedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Write sanitized output to a file
        PrintWriter out = new PrintWriter("output.html");
        out.println("<html>");
        out.println("<head><title>Secure Page</title></head>");
        out.println("<body>");
        out.println("<h1>Hello, " + sanitizedUserInput + "</h1>"); // Sanitized user input included in the HTML response
        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
